import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line: continue
    try:
        d = json.loads(line)
        msg = d.get('0','')
        t = d.get('time','')[-8:]
        lvl = d.get('_meta',{}).get('logLevelName','')
        if msg: print(f'{t} [{lvl}] {msg}')
    except: print(line[:100])
"

